const results = $input.all().map(i => i.json).filter(r => r && r.id);
const meaningful = results.filter(r => (r.content || '').trim().length >= 40);

// Enviamos el top 8 para reranking
const candidates = meaningful
  .sort((a, b) => (b.combined_score || 0) - (a.combined_score || 0))
  .slice(0, 8);

const formatted = candidates.map((c, i) => `[FRAGMENTO #${i}]\n${c.content}`).join('\n\n');

return [{ json: { 
  query: $('Extraer_Plan').item.json.querySearch || $('input').item.json.query,
  candidates_text: formatted,
  candidates_raw: candidates,
  all_results: results
} }];

const inputData = $('Filtrar_Candidatos').item.json;
const candidates = inputData.candidates_raw;
const allResults = inputData.all_results;

try {
  // CORRECCIÓN: Leer de $json.output que es donde el AI Agent entrega el texto
  const cleanText = $json.output || '';
  const data = JSON.parse(cleanText);
  const selectedIndices = data.indices || [];

  const relevantResults = selectedIndices.map(i => candidates[i]).filter(Boolean);
  if (relevantResults.length === 0 && candidates.length > 0) {
    relevantResults.push(candidates[0]);
  }

  const seen = new Set();
  const sourceUrls = [], pageNumbers = [], excludeIds = allResults.map(r => r.id).filter(Boolean);

  for (const r of relevantResults) {
    const src = r.metadata?.source_url || '';
    const pn = r.metadata?.page_number || 0;
    const key = `${src}|${pn}`;
    if (src && !seen.has(key)) {
      seen.add(key);
      sourceUrls.push(src);
      pageNumbers.push(pn);
    }
  }

  return [{ json: {
    originalResults: allResults,
    relevantResults: relevantResults,
    indices_utilizados: selectedIndices,
    needsExpansion: sourceUrls.length > 0,
    expansionParams: {
      p_source_urls: sourceUrls,
      p_page_numbers: pageNumbers,
      p_exclude_ids: excludeIds,
      p_window: 1
    }
  } }];
} catch (e) {
  return [{ json: {
    originalResults: allResults,
    relevantResults: [candidates[0]],
    needsExpansion: !!candidates[0],
    error: e.message,
    expansionParams: {
      p_source_urls: candidates[0]?.metadata?.source_url ? [candidates[0].metadata.source_url] : [],
      p_page_numbers: candidates[0]?.metadata?.page_number ? [candidates[0].metadata.page_number] : [],
      p_exclude_ids: allResults.map(r => r.id).filter(Boolean),
      p_window: 1
    }
  } }];
}

const { contexto, images, query, sourceUrl, chat_id } = $json;
const hasImage = !!$('input').item.json.image_base64;
const imageData = $('input').item.json.image_base64 || null;
const imageMimeType = $('input').item.json.image_mime_type || 'image/jpeg';
const userName = $('input').item.json.userName || 'Usuario';
const fecha = new Date().toLocaleDateString('es-MX', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

const imageListForPrompt = images && images.length > 0
  ? '\n\nIMÁGENES TÉCNICAS DISPONIBLES EN EL MANUAL:\n' + images.map(img => '  [' + img.index + '] ' + img.filename).join('\n') + '\nSi el usuario solicita visuales o si una imagen ayuda a explicar, inclúyela usando: [ENVIAR_IMAGENES: N].'
  : '';

const systemInstruction = `FECHA ACTUAL: ${fecha}\nEres SARA, la asistente técnica experta de Satcom. Tu objetivo es resolver dudas utilizando la documentación técnica proporcionada.\n\nINSTRUCCIONES DE CONOCIMIENTO:\n1. La información bajo 'DOCUMENTACIÓN DE APOYO' es tu conocimiento interno. NO agradezcas al usuario por esta información.\n2. Responde directamente y de forma profesional basándote en la documentación.\n3. Si la respuesta no está en los fragmentos, indícalo claramente sin inventar.\n4. Estas hablando con ${userName}.\n\nREGLAS DE FORMATO:\n- Cita la fuente (Manual/Sección) solo cuando la respuesta provenga de la documentación.\n- Usa listas con viñetas para pasos técnicos.\n- Para imágenes del manual que aporten valor: [ENVIAR_IMAGENES: N].\n- NO inventes información.`;

