const match = finalResponse.match(regex);
let imageToSend = null;
if (match && imagesFromRAG.length > 0) {
  const indices = match[1].split(',').map(s => parseInt(s.trim())).filter(n => !isNaN(n));
  for (const idx of indices) {
    const img = imagesFromRAG[idx - 1];
    if (img && img.base64) { imageToSend = img.base64; break; }
  }
  finalResponse = finalResponse.replace(regex, '').trim();
}
const output = { json: { chat_id, final_response: finalResponse, source_url: sourceUrl, send_image: !!imageToSend } };
if (imageToSend) { output.binary = { data: { data: imageToSend, mimeType: 'image/jpeg', fileName: 'imagen_manual.jpg' } }; }
return [output];

const data = $('Procesar_Output').first().json;
const response = data.final_response || 'No encontré información relevante en los manuales.';
const sourceUrl = data.source_url || '';
const withLink = sourceUrl ? `${response}\\n\\n🔗 [Ver en el Manual Original](${sourceUrl})` : response;
return [{ json: { response: withLink } }];
